head.b:skin:
body {
  margin: 0;
  font-family: Arial, sans-serif;
  background: #000;
  color: #fff;
}
.sports-navbar {
  display: flex;
  align-items: center;
  overflow-x: auto;
  background-color: #111;
  padding: 12px 10px;
  white-space: nowrap;
  border-bottom: 1px solid #222;
}
.sports-navbar::-webkit-scrollbar {
  display: none;
}
.sports-navbar .logo {
  display: flex;
  align-items: center;
  font-size: 20px;
  font-weight: bold;
  margin-right: 20px;
}
.sports-navbar .logo a {
  color: #fff;
  text-decoration: none;
  font-size: inherit;
  font-weight: inherit;
  display: flex;
  align-items: center;
  transition: color 0.3s ease;
}
.sports-navbar .logo a:hover {
  color: #00e676;
}
.sports-navbar .logo img {
  height: 28px;
  margin-right: 10px;
}

.nav-links-wrapper {
  display: flex;
  align-items: center;
  overflow-x: auto;
  white-space: nowrap;
}
.nav-links-wrapper::-webkit-scrollbar {
  display: none;
}

.sports-navbar .nav-links-wrapper a {
  display: inline-flex;
  align-items: center;
  color: #ccc;
  text-decoration: none;
  font-size: 15px;
  margin-right: 16px;
  transition: color 0.3s ease;
}
.sports-navbar .nav-links-wrapper a:hover,
.sports-navbar .nav-links-wrapper a.nav-link-active {
  color: #00e676;
}
.sports-navbar .nav-links-wrapper a img {
  height: 22px;
  width: 22px;
  margin-right: 8px;
}

.clock-wrapper {
  display: inline-flex;
  align-items: center;
  margin-left: auto;
  padding-left: 20px;
}

/* Style for the new Date display */
.current-date-display {
  color: #ccc;
  font-size: 14px;
  margin-right: 10px;
  white-space: nowrap;
}

.digital-clock-display {
  color: #00e676;
  font-size: 15px;
  font-weight: bold;
  min-width: 75px;
  text-align: right;
  margin-right: 8px;
}

.clock-format-toggle-btn {
  color: #a0a0a0;
  font-size: 11px;
  font-weight: normal;
  cursor: pointer;
  padding: 3px 6px;
  border: 1px solid #333;
  border-radius: 4px;
  background-color: #222;
  transition: color 0.2s ease, background-color 0.2s ease;
  user-select: none;
  white-space: nowrap;
}
.clock-format-toggle-btn:hover {
  color: #fff;
  background-color: #00753a;
}

@media (min-width: 769px) {
  .nav-links-wrapper {
    margin-left: auto;
    margin-right: auto;
  }
}

@media (max-width: 768px) {
  .sports-navbar {
    flex-wrap: wrap;
    justify-content: space-between;
    overflow-x: hidden;
    white-space: normal;
    padding: 10px;
  }
  .sports-navbar .logo {
    order: 1;
    margin-right: 10px;
    font-size: 18px;
  }
  .sports-navbar .logo img {
    height: 24px;
  }
  .clock-wrapper {
    order: 2;
    margin-left: 10px;
    padding-left: 0;
    /* Consider flex-shrink: 0; if items get too squeezed by a long logo text */
    /* flex-shrink: 0; */
  }
  .current-date-display {
    font-size: 12px;
    margin-right: 8px;
  }
  .digital-clock-display {
    font-size: 13px; /* Adjusted */
    min-width: auto;
    margin-right: 5px;
  }
  .clock-format-toggle-btn {
    font-size: 9px; /* Adjusted */
    padding: 2px 3px; /* Adjusted */
  }
  .nav-links-wrapper {
    order: 3;
    width: 100%;
    margin-top: 10px;
    padding-bottom: 8px;
    justify-content: center;
  }
  .nav-links-wrapper::-webkit-scrollbar {
    height: 5px;
    display: block !important;
  }
  .nav-links-wrapper::-webkit-scrollbar-thumb {
    background: #555;
    border-radius: 3px;
  }
  .nav-links-wrapper::-webkit-scrollbar-track {
    background: #222;
  }
  .sports-navbar .nav-links-wrapper a {
    font-size: 14px;
    margin-right: 12px;
  }
  .sports-navbar .nav-links-wrapper a img {
    height: 20px;
    width: 20px;
  }
  .nav-links-wrapper a:last-child {
    margin-right: 0;
  }
  .footer-container {
    padding-left: 5px;
    padding-right: 5px;
  }
  .notice-bar {
    font-size: 13px;
    padding: 8px;
    margin-bottom: 10px;
  }
  .footer-menu a {
    font-size: 13px;
    margin: 5px 10px;
  }
}

.site-footer {
  background-color: #111;
  color: #ccc;
  padding: 25px 15px;
  border-top: 1px solid #222;
  text-align: center;
  margin-top: 40px;
}
.footer-container {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.notice-bar {
  background-color: #000;
  color: #00e676;
  padding: 12px 15px;
  margin-bottom: 20px;
  border-radius: 4px;
  font-size: 14px;
  width: 100%;
  max-width: 800px;
  box-sizing: border-box;
}
.notice-bar p {
  margin: 0;
  padding: 0;
}
.footer-menu {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  align-items: center;
}
.footer-menu a {
  color: #aaa;
  text-decoration: none;
  margin: 8px 15px;
  font-size: 14px;
  transition: color 0.3s ease;
}
.footer-menu a:hover {
  color: #00e676;
}
.feed-links {
  display: none !important;
}

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//

body.script:
//
  let is24HourFormat = false;

  function updateDateDisplay() {
    const now = new Date();
    const options = { weekday: 'short', month: 'short', day: 'numeric' };
    const dateString = now.toLocaleDateString(undefined, options);
    const dateElement = document.getElementById('current-date');
    if (dateElement) {
      dateElement.textContent = dateString;
    }
  }

  function updateClockDisplay() {
    const now = new Date();
    let hours = now.getHours();
    const minutes = now.getMinutes().toString().padStart(2, '0');
    let timeString;
    if (is24HourFormat) {
      const hours24 = hours.toString().padStart(2, '0');
      timeString = `${hours24}:${minutes}`;
    } else {
      const ampm = hours >= 12 ? 'PM' : 'AM';
      hours = hours % 12;
      hours = hours ? hours : 12;
      const hours12 = hours.toString().padStart(2, '0');
      timeString = `${hours12}:${minutes} ${ampm}`;
    }
    const clockElement = document.getElementById('digital-clock');
    if (clockElement) clockElement.textContent = timeString;

    if (now.getHours() === 0 && now.getMinutes() === 0 && now.getSeconds() === 0) {
      updateDateDisplay();
    }
  }

  function toggleClockFormat() {
    is24HourFormat = !is24HourFormat;
    updateClockDisplay();
    const toggleButton = document.getElementById('clock-format-toggle');
    if (toggleButton) toggleButton.textContent = is24HourFormat ? "(12h)" : "(24h)";
  }

  function initializeClockAndToggle() {
    const toggleButtonElement = document.getElementById('clock-format-toggle');
    if (toggleButtonElement) {
      toggleButtonElement.addEventListener('click', toggleClockFormat);
      toggleButtonElement.textContent = is24HourFormat ? "(12h)" : "(24h)";
    }
    updateDateDisplay();
    updateClockDisplay();
    setInterval(updateClockDisplay, 1000);
  }

  function initializeNavLinkActivation() {
    const navLinksContainer = document.querySelector('.nav-links-wrapper');
    if (!navLinksContainer) return;

    const navLinks = navLinksContainer.querySelectorAll('a');
    const currentUrl = window.location.href;

    const normalizeUrl = (urlString) => {
        try {
            const urlObj = new URL(urlString, window.location.origin);
            return (urlObj.origin + urlObj.pathname.replace(/\/$/, '')).toLowerCase();
        } catch (e) {
            return (urlString.replace(/\/$/, '')).toLowerCase();
        }
    };

    const normalizedCurrentUrl = normalizeUrl(currentUrl);

    navLinks.forEach(link => {
      link.classList.remove('nav-link-active');
    });

    let activeLinkFound = false;
    navLinks.forEach(link => {
      if (link.href && link.getAttribute('href') !== '#') {
          const normalizedLinkHref = normalizeUrl(link.href);
          if (normalizedLinkHref === normalizedCurrentUrl) {
            link.classList.add('nav-link-active');
            activeLinkFound = true;
          }
      }
    });

    navLinks.forEach(link => {
      link.addEventListener('click', function(event) {
        if (this.getAttribute('href') === '#') {
          event.preventDefault();
          navLinks.forEach(l => l.classList.remove('nav-link-active'));
          this.classList.add('nav-link-active');
        }
      });
    });
  }

  if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', function() {
          initializeClockAndToggle();
          initializeNavLinkActivation();
      });
  } else {
      initializeClockAndToggle();
      initializeNavLinkActivation();
  }
//

b:if.script:
//
  document.addEventListener('DOMContentLoaded', function() {
    const homeLink = document.getElementById('home-link');
    if (homeLink) {
      const allNavLinks = document.querySelectorAll('.nav-links-wrapper a');
      allNavLinks.forEach(link => {
        link.classList.remove('nav-link-active');
      });
      homeLink.classList.add('nav-link-active');
    }
  });
