body.script:
var ctrlUTries = 0;

document.addEventListener('keydown', function(e) {
  var key = e.key.toLowerCase();

  if (e.ctrlKey && key === 'u') {
    e.preventDefault();
    e.stopPropagation();
    ctrlUTries++;

    if (ctrlUTries >= 1) {
      window.location.href = "https://khelaview.blogspot.com/p/contact.html";
    }
    return false;
  }

  if (key === "f12" || (e.ctrlKey && e.shiftKey && key === 'i')) {
    e.preventDefault();
    e.stopPropagation();
    window.location.href = "https://khelaview.blogspot.com/";
  }
});

document.addEventListener('contextmenu', function(e) {
  e.preventDefault();
});

(function() {
  var devtoolsOpen = false;
  var threshold = 160;

  function detectDevTools() {
    var widthThreshold = window.outerWidth - window.innerWidth > threshold;
    var heightThreshold = window.outerHeight - window.innerHeight > threshold;

    if (widthThreshold || heightThreshold) {
      if (!devtoolsOpen) {
        devtoolsOpen = true;
        window.location.href = "https://khelaview.blogspot.com/p/contact.html";
      }
    } else {
      devtoolsOpen = false;
    }
  }

  setInterval(detectDevTools, 1000);

  setInterval(function() {
    var start = new Date();
    debugger;
    var end = new Date();
    if (end - start > 100) {
      if (!devtoolsOpen) {
        devtoolsOpen = true;
        window.location.href = "https://khelaview.blogspot.com/p/contact.html";
      }
    }
  }, 2000);
})();

// 
(function() {
  if (sessionStorage.getItem('popupShown')) {
    // Popup already shown this session, do nothing
    return;
  }

  var style = document.createElement("style");
  style.textContent = `
    #glassBackdrop {
      position: fixed;
      inset: 0;
      background: rgba(0,0,0,0.3);
      backdrop-filter: blur(5px);
      z-index: 9998;
      animation: fadeIn 0.3s ease forwards;
    }
    #glassPopup {
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%) scale(0.9);
      background: rgba(255, 255, 255, 0.2);
      backdrop-filter: blur(15px);
      border-radius: 20px;
      padding: 30px;
      box-shadow: 0 8px 25px rgba(0, 0, 0, 0.2);
      text-align: center;
      color: #fff;
      font-family: Segoe UI, sans-serif;
      z-index: 9999;
      width: 85%;
      max-width: 360px;
      opacity: 0;
      animation: fadeInPopup 0.4s ease forwards;
    }
    #glassPopup h2 {
      margin-top: 0;
      font-size: 24px;
      color: #fff;
    }
    #glassPopup p {
      font-size: 16px;
      margin: 15px 0;
    }
    #glassPopup button {
      margin-top: 15px;
      padding: 10px 20px;
      background: #00bcd4;
      border: none;
      border-radius: 25px;
      color: #fff;
      font-size: 15px;
      cursor: pointer;
      transition: background 0.3s;
    }
    #glassPopup button:hover {
      background: #0097a7;
    }
    @keyframes fadeIn {
      to {opacity: 1;}
    }
    @keyframes fadeInPopup {
      to {
        opacity: 1;
        transform: translate(-50%, -50%) scale(1);
      }
    }
  `;
  document.head.appendChild(style);

  var backdrop = document.createElement("div");
  backdrop.id = "glassBackdrop";

  var popup = document.createElement("div");
  popup.id = "glassPopup";

  // Check if user visited before
  var visitedBefore = localStorage.getItem('visitedBefore');

  if (!visitedBefore) {
    // First time visitor popup
    popup.innerHTML = "<h2>🚨 Important</h2><p>This website uses cookies and local storage for better performance.</p><button id='popupCloseBtn'>OK, Got It</button>";
  } else {
    // Returning visitor popup (new session)
    popup.innerHTML = "<h2>👋 Welcome Back</h2><p>Thanks for visiting again! Enjoy your time here.</p><button id='popupCloseBtn'>Close</button>";
  }

  document.body.appendChild(backdrop);
  document.body.appendChild(popup);

  document.getElementById("popupCloseBtn").addEventListener("click", function() {
    popup.remove();
    backdrop.remove();

    // Mark popup shown for this session
    sessionStorage.setItem("popupShown", "true");

    // If first time visitor, mark visitedBefore for localStorage
    if (!visitedBefore) {
      localStorage.setItem("visitedBefore", "true");
    }
  });
})();
//
